/** 数秘術（ライフパスナンバー）の計算と診断 */

export interface NumerologyResult {
  lifePathNumber: number;
  title: string;
  /** 基本性格の詳細解説（300文字以上） */
  description: string;
  /** 気質・本質 */
  temperament: string;
  /** 行動パターン */
  behaviorPattern: string;
  /** 対人傾向・コミュニケーション */
  interpersonal: string;
  /** 恋愛傾向（300文字以上） */
  loveAnalysis: string;
  /** 数字の持つ意味 */
  numberMeaning: string;
  strengths: string[];
  weaknesses: string[];
  compatibility: number[];
  /** キャリア適性分析（プレミアム） */
  careerAnalysis: string;
  /** 向いている職種（プレミアム） */
  suitableCareers: string[];
  /** 人を惹きつける強み（プレミアム） */
  attractionStrength: string;
  /** 隠れた才能（プレミアム） */
  hiddenTalent: string;
  /** 相性の良いタイプ詳細分析（プレミアム） */
  compatibleType: string;
  /** 金運傾向（プレミアム） */
  moneyFortune: string;
  /** 人生の方向性（プレミアム） */
  lifeDirection: string;
  /** 今年の転機（プレミアム） */
  yearlyTurningPoint: string;
  /** 今後の伸ばし方（プレミアム） */
  growthAdvice: string;
}

/** 数字を1桁（またはマスターナンバー11,22,33）になるまで足す */
function reduceToSingle(n: number): number {
  while (n > 9 && n !== 11 && n !== 22 && n !== 33) {
    n = String(n).split('').reduce((sum, d) => sum + Number(d), 0);
  }
  return n;
}

/** ライフパスナンバーを計算する */
export function calculateLifePathNumber(year: number, month: number, day: number): number {
  const y = reduceToSingle(year);
  const m = reduceToSingle(month);
  const d = reduceToSingle(day);
  return reduceToSingle(y + m + d);
}

